-- ============================================================
-- Copa dos Sonhos — Squads históricos v3
-- Campeões e vice-campeões de todas as Copas 1970–2022
-- UUIDs 100% hex-válidos
-- Não faz TRUNCATE — apenas INSERT com ON CONFLICT DO NOTHING
-- ============================================================
-- Legenda de country codes usados nos UUIDs (2 hex chars):
--   de = Alemanha · a1 = Argentina · b1 = Holanda
--   c1 = Itália   · f5 = França    · c6 = Croácia
-- Squad pattern : 2[yr2][cc]000-0000-4000-8000-000000000001
-- Player pattern: 3[yr2][cc][pp]-0000-4000-8000-000000000001  pp=01..0b (hex)
-- ============================================================

-- ============================================================
-- EDIÇÕES (apenas as ainda ausentes do banco)
-- ============================================================
ON CONFLICT (id) DO NOTHING;

